$data = Get-Content "btc_data.json" | ConvertFrom-Json$dataset = @()# We predict next candle direction based on current candlefor ($i = 5; $i -lt ($data.Count - 1); $i++) {    # last 5 candles as input    $inputCandles = $data[($i-5)..$i]    $currentClose = [double]$data[$i][4]    $nextClose = [double]$data[$i+1][4]    # label creation    if ($nextClose -gt $currentClose * 1.001) {        $label = "BUY"    }    elseif ($nextClose -lt $currentClose * 0.999) {        $label = "SELL"    }    else {        $label = "HOLD"    }    $dataset += @{        input = $inputCandles        label = $label    }}$dataset | ConvertTo-Json -Depth 5 | Out-File "dataset.json"Write-Host "dataset.json created with $($dataset.Count) samples"